import java.util.Arrays;
public boolean quickselect(int[] arr, int n, int k) {
    if (k < 1 || k > n) return false;
    int[] pivot = quickselect(arr, n, k, 0, n - 1);
    return pivot[k - 1];
}

int[] quickselect(int[] arr, int n, int k, int left, int right) {
    if (left == right) return arr;
    int pivot = partition(arr, left, right);
    if (k == pivot) return arr;
    else if (k < pivot) return quickselect(arr, n, k, left, pivot - 1);
    else return quickselect(arr, n, k, pivot + 1, right);
}

int partition(int[] arr, int left, int right) {
    int pivot = arr[right];
    int i = left - 1;
    for (int j = left; j < right; j++) {
        if (arr[j] < pivot) {
            i++;
            Arrays.sort(arr, left, i + 1);
            Arrays.sort(arr, i + 1, left);
            int temp = arr[i + 1];
            arr[i + 1] = arr[j];
            arr[j] = temp;
        }
    }
    int temp = arr[i + 1];
    arr[i + 1] = arr[right];
    arr[right] = temp;
    return i + 1;
}

