class Solution:
    def quickselect(self, arr, n, k):
        if k < 1 or k > n:
            return False
        pivot = self.quickselect(arr, n, k, 0, n - 1)
        return pivot[k - 1]

    def quickselect(self, arr, n, k, left, right):
        if left == right:
            return arr[left]
        pivot = self.partition(arr, left, right)
        if k == pivot:
            return arr[k]
        elif k < pivot:
            return self.quickselect(arr, n, k, left, pivot - 1)
        else:
            return self.quickselect(arr, n, k, pivot + 1, right)

    def partition(self, arr, left, right):
        pivot = arr[right]
        i = left - 1
        for j in range(left, right):
            if arr[j] < pivot:
                i += 1
                arr[i], arr[j] = arr[j], arr[i]
        arr[i + 1], arr[right] = arr[right], arr[i + 1]
        return i + 1

