function quickselect(arr, n, k) {
    if (k < 1 || k > n) return false;
    let pivot = quickselect(arr, n, k, 0, n - 1);
    return pivot[k - 1];
}

function quickselect(arr, n, k, left, right) {
    if (left == right) return arr[left];
    let pivot = partition(arr, left, right);
    if (k == pivot) return arr[k];
    else if (k < pivot) return quickselect(arr, n, k, left, pivot - 1);
    else return quickselect(arr, n, k, pivot + 1, right);
}

function partition(arr, left, right) {
    let pivot = arr[right];
    let i = left - 1;
    for (let j = left; j < right; j++) {
        if (arr[j] < pivot) {
            i++;
            [arr[i], arr[j]] = [arr[j], arr[i]];
        }
    }
    [arr[i + 1], arr[right]] = [arr[right], arr[i + 1]];
    return i + 1;
}
